			steps.push([
				[...addStep(crtPolynom, degree,false)],
				[...addStep(zeroPolynom, maxDegreeRight)]
			])
		}
		
		return {
			numerator: N,
			denominator: D,
			euclidian,
			table: {
				steps,
				underline
			}
		}
		
	} catch (e) {
		console.error(e)
		return false
	}
})

